-- ── DDL ──────────────────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS workday_resumo (
  workday_id            integer PRIMARY KEY,
  data                  date,
  unidade_id            integer,
  acessos               integer,
  permanencia           numeric,
  cmv_pct               integer,
  ticket_zero           numeric,
  ticket_real           numeric,
  ticket_medio          numeric,
  bruto                 numeric,
  desconto              numeric,
  gorjeta               numeric,
  custo                 numeric,
  despesa               numeric,
  lucro                 numeric,
  convite               numeric,
  produto               numeric,
  consumo_total         numeric,
  devedor_total         numeric,
  pendencia_antiga      numeric,
  total_fechado         numeric,
  total_recebido        numeric,
  diferenca_caixa       numeric,
  diferenca_real        numeric,
  cancelamentos_total   numeric,
  descontos_total       numeric,
  devedores             numeric,
  pendencias_antigas    numeric,
  pagamentos            jsonb,
  caixas                jsonb,
  ambientes             jsonb,
  turnos                jsonb,
  clientes_tipo         jsonb,
  clientes_sexo         jsonb,
  clientes_idade        jsonb,
  cidades               jsonb,
  gorjetas_edit         jsonb,
  descontos_motivo      jsonb,
  cancelamentos_motivo  jsonb,
  cancelamentos_usuario jsonb,
  created_at            timestamptz DEFAULT now(),
  updated_at            timestamptz DEFAULT now()
);

CREATE TABLE IF NOT EXISTS workday_caixas (
  caixa_id       integer PRIMARY KEY,
  workday_id     integer REFERENCES workday_resumo(workday_id) ON DELETE CASCADE,
  operador_nome  text,
  operador_cpf   text,
  abertura       timestamptz,
  fechamento     timestamptz,
  total_fechado  numeric,
  total_recebido numeric,
  diferenca_total numeric,
  dinheiro_total numeric,
  despesa        numeric,
  transacao      numeric,
  pagamentos     jsonb,
  cedulas        jsonb,
  moedas         jsonb
);

CREATE TABLE IF NOT EXISTS workday_produtos (
  id         integer PRIMARY KEY,
  workday_id integer REFERENCES workday_resumo(workday_id) ON DELETE CASCADE,
  posicao    integer,
  nome       text,
  qtde       numeric,
  unitario   numeric,
  cmv_pct    integer,
  custo      numeric,
  lucro      numeric,
  consumo    numeric
);

CREATE TABLE IF NOT EXISTS workday_grupos (
  id         integer PRIMARY KEY,
  workday_id integer REFERENCES workday_resumo(workday_id) ON DELETE CASCADE,
  posicao    integer,
  nome       text,
  percentual integer,
  bruto      numeric,
  desconto   numeric,
  gorjeta    numeric,
  consumo    numeric
);

CREATE TABLE IF NOT EXISTS workday_usuarios (
  id         integer PRIMARY KEY,
  workday_id integer REFERENCES workday_resumo(workday_id) ON DELETE CASCADE,
  posicao    integer,
  nome       text,
  qtde       numeric,
  gorjeta    numeric,
  convite    numeric,
  produto    numeric,
  consumo    numeric
);

CREATE TABLE IF NOT EXISTS workday_venda (
  workday_id     integer PRIMARY KEY REFERENCES workday_resumo(workday_id) ON DELETE CASCADE,
  data           date,
  bruto_total    numeric,
  desconto_total numeric,
  gorjeta_total  numeric,
  total          numeric,
  categorias     jsonb
);

CREATE TABLE IF NOT EXISTS titulos_a_pagar (
  id                    uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  tipo                  text,
  n_nota_fiscal         text,
  fantasia_fornecedor   text,
  razao_fornecedor      text,
  cnpj_cpf_fornecedor   text,
  t_fornecedor          text,
  descricao_c_gerencial text,
  n_titulo              text,
  parcela               text,
  portador              text,
  d_lancamento          date,
  d_competencia         date,
  d_vencimento          date,
  v_titulo              numeric,
  v_saldo_atual         numeric,
  dias_atraso_atual     integer,
  situacao_atual        text,
  tipo_sep              text,
  fluxo_de_caixa        boolean DEFAULT false,
  importado_em          timestamptz,
  ref_mes               date
);

CREATE TABLE IF NOT EXISTS vendas_diarias (
  id                   integer PRIMARY KEY,
  data_venda           date NOT NULL,
  turno                text NOT NULL,
  qtd_clientes         integer,
  faturamento_bruto    numeric,
  gorjetas             numeric,
  descontos_clientes   numeric,
  descontos_socios     numeric,
  descontos_internos   numeric,
  penduras             numeric,
  perdas               numeric,
  meta_faturamento     numeric,
  criado_em            timestamp DEFAULT now()
);

CREATE TABLE IF NOT EXISTS metas_projecoes (
  id               integer PRIMARY KEY,
  mes_ano          text NOT NULL,
  meta_faturamento numeric,
  criado_em        timestamptz DEFAULT now(),
  metas_diarias    jsonb
);

CREATE TABLE IF NOT EXISTS notas_nutri (
  id              integer PRIMARY KEY,
  data_inspecao   date,
  local           text,
  tipo_inspecao   text,
  nota            numeric,
  status          text
);

CREATE TABLE IF NOT EXISTS auditoria_nutricional (
  id              integer PRIMARY KEY,
  data_inspecao   date,
  nota            numeric,
  status          text,
  criado_em       timestamptz DEFAULT now(),
  local           text,
  tipo_inspecao   text
);

CREATE TABLE IF NOT EXISTS notas_detalhadas (
  id              integer PRIMARY KEY,
  local           text,
  topico          text,
  setor           text,
  data_inspecao   date,
  meta            numeric,
  nota            numeric
);


